1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	};
7	
8	type Item = { type: string };
9	type QuoteStep = { op: "quote"; items: Item[] };
10	type Step = QuoteStep;
11	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
12	
13	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
14	
15	const quotePremium = (items: Item[]): number =>
16	  items.reduce((sum, item) => sum + basePremiumFor(item), 0) + PROCESSING_FEE;
17	
18	export const processScenario = (input: Scenario): unknown => {
19	  const results = input.steps.map((step) => ({
20	    premium: quotePremium(step.items),
21	  }));
22	  return { results };
23	};
