44	  // ---------- 'Alike' components (❓ same type, not just family) ----------
45	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
46	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
